// Get Gemini's response text
const geminiResponse = $input.first().json.content.parts[0].text;

// Clean it up — remove markdown backticks if any
const cleaned = geminiResponse
  .replace(/```json/g, '')
  .replace(/```/g, '')
  .trim();

// Parse it into proper JSON
let memo = JSON.parse(cleaned);

// Add extra fields
memo.account_id = "account_001";
memo.version = "v1";
memo.source = "demo_call";
memo.generated_at = new Date().toISOString();

// Convert to binary so Write File node can save it
const binaryData = await this.helpers.prepareBinaryData(
  Buffer.from(JSON.stringify(memo, null, 2)),
  'account_memo.json',
  'application/json'
);

return {
  json: memo,
  binary: {
    data: binaryData
  }
};

// Get Gemini's agent spec response
const geminiResponse = $input.first().json.content.parts[0].text;

// Clean markdown if any
const cleaned = geminiResponse
  .replace(/```json/g, '')
  .replace(/```/g, '')
  .trim();

// Parse JSON
let agentSpec = JSON.parse(cleaned);

// Add metadata
agentSpec.account_id = "account_001";
agentSpec.version = "v1";
agentSpec.generated_at = new Date().toISOString();

// Convert to binary for saving
const binaryData = await this.helpers.prepareBinaryData(
  Buffer.from(JSON.stringify(agentSpec, null, 2)),
  'agent_spec.json',
  'application/json'
);

return {
  json: agentSpec,
  binary: {
    data: binaryData
  }
};
